/*
 * atanh() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly atanh  (test_atanh_opt.elf)
 *   2. Linked with toolchain's default atanh       (test_atanh_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

static volatile double g_acc;

static void emit(double x)
{
#ifdef EN_PERF
    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    g_acc += atanh(vx);
#else
    double r = atanh(x);
    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
#endif
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}

/* ------------------------------------------------------------------ */
/* test_representative_100: 100 representative inputs for atanh        */
/* atanh domain: (-1, 1); poles at +-1; atanh(x) ~ x for small x      */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0);
    emit(-0.0);
    emit_u(0x7ff8000000000000ULL);  /* qNaN */
    emit_u(0x7ff0000000000001ULL);  /* sNaN */
    emit_u(0xfff8000000000000ULL);  /* -qNaN */
    emit_u(0x7ff0000000000000ULL);  /* +Inf (out of domain) */
    emit_u(0xfff0000000000000ULL);  /* -Inf (out of domain) */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x0000000000000001ULL);  /* min positive subnormal: 2^-1074 */
    emit_u(0x8000000000000001ULL);  /* min negative subnormal */
    emit_u(0x0008000000000000ULL);  /* mid positive subnormal */
    emit_u(0x8008000000000000ULL);  /* mid negative subnormal */
    emit_u(0x000fffffffffffffULL);  /* max positive subnormal: just below DBL_MIN */
    emit_u(0x800fffffffffffffULL);  /* max negative subnormal */

    /* --- Section 3: Normal boundaries and out-of-domain values (6) --- */
    emit(DBL_MIN);                  /* smallest normal: 2^-1022 */
    emit(-DBL_MIN);
    emit_u(0x0010000000000001ULL);  /* one ULP above DBL_MIN */
    emit(2.0);                      /* outside domain: |x| > 1 -> NaN */
    emit(-2.0);                     /* outside domain */
    emit_u(0x7fefffffffffffffULL);  /* DBL_MAX: far outside domain */

    /* --- Section 4: ULP neighbors of +1.0 (the positive pole) (9) --- */
    emit_u(0x3fefffffffffffffULL);  /* 1.0 - 1 ULP: just inside domain */
    emit_u(0x3feffffffffffffeULL);  /* 1.0 - 2 ULP */
    emit_u(0x3feffffffffffffdULL);  /* 1.0 - 3 ULP */
    emit(1.0);                      /* exactly +1.0: pole -> +Inf */
    emit_u(0x3ff0000000000001ULL);  /* 1.0 + 1 ULP: outside domain -> NaN */
    emit_u(0x3ff0000000000002ULL);  /* 1.0 + 2 ULP: outside domain */
    emit_u(0x3ff0000000000010ULL);  /* 1.0 + several ULP */
    emit_u(0x3ff0000000000100ULL);  /* 1.0 + many ULP */
    emit_u(0x3ff0000000001000ULL);  /* moderately above 1.0 */

    /* --- Section 5: ULP neighbors of -1.0 (the negative pole) (6) --- */
    emit_u(0xbfefffffffffffffULL);  /* -1.0 + 1 ULP: just inside domain */
    emit_u(0xbfeffffffffffffeULL);  /* -1.0 + 2 ULP */
    emit(-1.0);                     /* exactly -1.0: pole -> -Inf */
    emit_u(0xbff0000000000001ULL);  /* -1.0 - 1 ULP: outside domain */
    emit_u(0xbff0000000000002ULL);  /* -1.0 - 2 ULP: outside domain */
    emit(-1.5);                     /* clearly outside domain */

    /* --- Section 6: Uniformly spaced values across domain (14) --- */
    emit(0.1);
    emit(-0.1);
    emit(0.2);
    emit(-0.2);
    emit(0.3);
    emit(-0.3);
    emit(0.4);
    emit(-0.4);
    emit(0.6);
    emit(-0.6);
    emit(0.7);
    emit(-0.7);
    emit(0.8);
    emit(-0.8);

    /* --- Section 7: Near-zero fast-path boundaries (8) --- */
    /* atanh(x) ~ x for tiny x; implementations often have a threshold */
    emit_u(0x3cb0000000000000ULL);  /* 2^-52: one ULP of 1.0, near identity threshold */
    emit_u(0xcb0000000000000ULL);   /* -2^-52 */
    emit_u(0x3e50000000000000ULL);  /* 2^-26: typical Taylor-series threshold */
    emit_u(0xbe50000000000000ULL);  /* -2^-26 */
    emit_u(0x3f20000000000000ULL);  /* 2^-13 */
    emit_u(0xbf20000000000000ULL);  /* -2^-13 */
    emit_u(0x3f80000000000000ULL);  /* 2^-7 = 0.0078125 */
    emit_u(0xbf80000000000000ULL);  /* -2^-7 */

    /* --- Section 8: ULP neighbors of 0.5 (polynomial switch point) (9) --- */
    /* Many atanh implementations use different polynomials for |x| < 0.5 */
    emit_u(0x3fdffffffffffffeULL);  /* 0.5 - 2 ULP */
    emit_u(0x3fdfffffffffffffULL);  /* 0.5 - 1 ULP */
    emit(0.5);                      /* exactly 0.5: atanh(0.5) = ln(3)/2 ~ 0.5493 */
    emit_u(0x3fe0000000000001ULL);  /* 0.5 + 1 ULP */
    emit_u(0x3fe0000000000002ULL);  /* 0.5 + 2 ULP */
    emit_u(0xbfdffffffffffffeULL);  /* -0.5 - 2 ULP (toward zero) */
    emit_u(0xbfdfffffffffffffULL);  /* -0.5 - 1 ULP */
    emit(-0.5);                     /* exactly -0.5 */
    emit_u(0xbfe0000000000001ULL);  /* -0.5 + 1 ULP (away from zero) */

    /* --- Section 9: Critical pole-approach region (12) --- */
    /* Values very close to +-1 where log(1-x^2) loses precision */
    emit(0.9);
    emit(-0.9);
    emit(0.99);
    emit(-0.99);
    emit(0.999);
    emit(-0.999);
    emit(0.9999);
    emit(-0.9999);
    emit(0.99999);
    emit(-0.99999);
    emit(0.999999);
    emit(-0.999999);

    /* --- Section 10: ULP triplets and stress bit patterns (23) --- */
    /* ULP triplet near 0.25 */
    emit_u(0x3fcfffffffffffffULL);  /* 0.25 - 1 ULP */
    emit(0.25);                     /* exactly 0.25 */
    emit_u(0x3fd0000000000001ULL);  /* 0.25 + 1 ULP */

    /* ULP triplet near 0.75 */
    emit_u(0x3fe7ffffffffffffULL);  /* 0.75 - 1 ULP */
    emit(0.75);                     /* exactly 0.75 */
    emit_u(0x3fe8000000000001ULL);  /* 0.75 + 1 ULP */

    /* ULP triplet near sqrt(2)/2 ~ 0.7071 (common test value for inverse trig) */
    emit_u(0x3fe6a09e667f3bccULL);  /* sqrt(2)/2 - 1 ULP */
    emit_u(0x3fe6a09e667f3bcdULL);  /* sqrt(2)/2 */
    emit_u(0x3fe6a09e667f3bceULL);  /* sqrt(2)/2 + 1 ULP */

    /* ULP triplet near sqrt(3)/2 ~ 0.8660 */
    emit_u(0x3febb67ae8584caaULL);  /* sqrt(3)/2 - 1 ULP */
    emit_u(0x3febb67ae8584cabULL);  /* sqrt(3)/2 */
    emit_u(0x3febb67ae8584cacULL);  /* sqrt(3)/2 + 1 ULP */

    /* Special bit patterns within domain */
    emit_u(0x3fe921fb54442d18ULL);  /* pi/4 ~ 0.7854: within domain */
    emit_u(0x3fd921fb54442d18ULL);  /* pi/8 ~ 0.3927: within domain */
    emit_u(0x3fb921fb54442d18ULL);  /* pi/32 ~ 0.0982 */
    emit_u(0xbfe921fb54442d18ULL);  /* -pi/4 */
    emit_u(0xbfd921fb54442d18ULL);  /* -pi/8 */

    /* Additional rational fractions */
    emit(0.125);                    /* 1/8 */
    emit(-0.125);
    emit(0.375);                    /* 3/8 */
    emit(-0.375);
    emit(0.625);                    /* 5/8 */
    emit(-0.625);
    emit(0.875);                    /* 7/8 */
    emit(-0.875);
}

#ifndef EN_PERF
/* 7. Sweep [-0.99, 0.99] in 200 steps */
static void test_sweep(void)
{
    double lo = -0.99;
    double hi = 0.99;
    int nsteps = 200;
    double step = (hi - lo) / (double)nsteps;

    for (int i = 0; i <= nsteps; i++)
        emit(lo + (double)i * step);
}

/* 8. Sample [0, 0.5] every 4194304 ULP (~250 cases) */
static void test_exhaustive_small(void)
{
    static const uint64_t vals[] = {
        0x0000000000000000ULL, /* 0.0 */
        0x3fb0000000000000ULL, /* 0.0625 */
        0x3fc0000000000000ULL, /* 0.125 */
        0x3fd0000000000000ULL, /* 0.25 */
        0x3fd8000000000000ULL, /* 0.375 */
        0x3fe0000000000000ULL, /* 0.5 */
    };
    for (int i = 0; i < (int)(sizeof(vals)/sizeof(vals[0])); i++)
        emit_u(vals[i]);
}
#endif

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf acc: %016llx\n", (unsigned long long)d2u((double)g_acc));
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
#endif
    return 0;
}

